export function kargoUcreti(firma, desi) {
  const d = Math.min(Math.ceil(+desi||1), 500);
  if (T[d] && T[d][firma]) return T[d][firma];
  const desiler = Object.keys(T).map(Number).sort((a,b)=>a-b);
  const enYakin = desiler.reduce((p,c) => Math.abs(c-d)<Math.abs(p-d)?c:p, desiler[0]);
  return T[enYakin]?.[firma] || 100.716;
}
